glsl3.vert:
precision highp float;
uniform CCGlobal {
  mat4 cc_matView;
  mat4 cc_matViewInv;
  mat4 cc_matProj;
  mat4 cc_matProjInv;
  mat4 cc_matViewProj;
  mat4 cc_matViewProjInv;
  vec4 cc_cameraPos;
  vec4 cc_time;
  mediump vec4 cc_screenSize;
  mediump vec4 cc_screenScale;
};
uniform CCLocal {
  mat4 cc_matWorld;
  mat4 cc_matWorldIT;
};
in vec3 a_position;
in vec4 a_color;
out vec4 v_color;
out vec4 fragPos;
#if USE_TEXTURE
in vec2 a_uv0;
out vec2 v_uv0;
#endif
void main () {
    vec4 pos = vec4(a_position, 1);
    #if CC_USE_MODEL
    pos = cc_matViewProj * cc_matWorld * pos;
    #else
    pos = cc_matViewProj * pos;
    #endif
    #if USE_TEXTURE
    v_uv0 = a_uv0;
    #endif
    v_color = a_color;
    gl_Position = pos;
    fragPos = pos;
}

glsl3.frag:
precision highp float;
#if USE_ALPHA_TEST
  uniform ALPHA_TEST {
    float alphaThreshold;
  };
#endif
void ALPHA_TEST (in vec4 color) {
  #if USE_ALPHA_TEST
      if (color.a < alphaThreshold) discard;
  #endif
}
void ALPHA_TEST (in float alpha) {
  #if USE_ALPHA_TEST
      if (alpha < alphaThreshold) discard;
  #endif
}
in vec4 v_color;
in vec4 fragPos;
#if USE_TEXTURE
in vec2 v_uv0;
uniform sampler2D texture;
#endif
uniform ARGS {
    vec4 center1;
    vec4 center2;
    vec4 center3;
    vec4 center4;
    float ambient_strength;
    float wh_ratio;
};
float getPointLight(vec4 v4){
  if(v4.a <= 0.0){
    return 1.0;
  }
  float dist = sqrt(pow(fragPos.x * wh_ratio - v4.r * wh_ratio, 2.0) + pow(fragPos.y - v4.g, 2.0));
  float r = smoothstep(v4.b * 0.2, v4.b * 1.0, dist);
  r = r + (1.0 - v4.a);
  if(r > 1.0){
    return 1.0;
  }
  if(r < 0.0){
    return 0.0;
  }
  return r;
}
float getPointLightOpacity(){
  float op = getPointLight(center1);
  float op2 = getPointLight(center2);
  op = op * op2;
  float op3 = getPointLight(center3);
  op = op * op3;
  float op4 = getPointLight(center4);
  op = op * op4;
  return op;
}
void main () {
    vec4 o = vec4(1, 1, 1, 1);
    #if USE_TEXTURE
  vec4 texture_tmp = texture(texture, v_uv0);
  #if CC_USE_ALPHA_ATLAS_texture
      texture_tmp.a *= texture(texture, v_uv0 + vec2(0, 0.5)).r;
  #endif
  #if INPUT_IS_GAMMA
    o.rgb *= (texture_tmp.rgb * texture_tmp.rgb);
    o.a *= texture_tmp.a;
  #else
    o *= texture_tmp;
  #endif
    #endif
    o *= v_color;
    ALPHA_TEST(o);
    float ambient = 1.0 - ambient_strength;
    float opacity = getPointLightOpacity();
    if(opacity > ambient){
      opacity = ambient;
    }
    gl_FragColor = o * opacity;
}

